#!/usr/bin/env python3
"""Block `pnpm test` (interactive vitest watcher); steer Claude to `pnpm test:ci`."""
import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    # Match `pnpm test` as a standalone subcommand, not `pnpm test:ci` or `pnpm test:foo`.
    if re.search(r"(^|[;&|]|&&|\|\|)\s*pnpm\s+test(\s|$)", cmd) and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` runs vitest in interactive watch mode and will hang waiting for a prompt (telemetry shows 3 timeouts at 120s).", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block direct shell writes to prisma/dev.db; steer to `prisma migrate`."""
import json, re, sys

DB_TOUCH = re.compile(r"(sqlite3\s+[^|;&]*prisma/dev\.db|(?:rm|mv|cp|>|>>)\s+[^|;&]*prisma/dev\.db)")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if DB_TOUCH.search(cmd):
        print("Refusing to touch prisma/dev.db directly. Schema changes must go through `prisma migrate` (see CLAUDE.md).", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Flag direct recursion in Python files after Write/Edit/MultiEdit."""
import ast, json, os, sys

def find_recursive_funcs(source):
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return []
    hits = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            name = node.name
            for sub in ast.walk(node):
                if isinstance(sub, ast.Call):
                    fn = sub.func
                    if isinstance(fn, ast.Name) and fn.id == name:
                        hits.append((name, sub.lineno))
                        break
    return hits

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0
    try:
        with open(path, "r", encoding="utf-8") as f:
            source = f.read()
    except Exception:
        return 0
    hits = find_recursive_funcs(source)
    if not hits:
        return 0
    print("Direct recursion detected in edited file:", file=sys.stderr)
    for name, lineno in hits:
        print(f"  {path}:{lineno} function `{name}` calls itself", file=sys.stderr)
    print("Confirm input depth is bounded (consider iterative form with an explicit worklist, or sys.setrecursionlimit + depth guard). Prior incident: walk_tree refactor hit RecursionError on a 2000-leaf tree.", file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Python edits, run `ruff format` then `ruff check`; feed failures back."""
import json, os, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "Write", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    try:
        subprocess.run(["ruff", "format", path], capture_output=True, text=True, timeout=10)
        chk = subprocess.run(["ruff", "check", path], capture_output=True, text=True, timeout=10)
    except FileNotFoundError:
        return 0
    except Exception:
        return 0
    if chk.returncode != 0:
        print(f"ruff check failed for {path} after auto-format:", file=sys.stderr)
        out = (chk.stdout or "") + (chk.stderr or "")
        for line in out.splitlines()[:40]:
            print(f"  {line}", file=sys.stderr)
        print("Fix the reported issues before continuing.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit/Write on a line that defines an exported identifier,
grep for references and feed the list back to Claude so it can verify
consistency across hardcoded callers."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum|default\s+(?:function|class))\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}

    if tool == "Write":
        edits = [{"old_string": "", "new_string": inp.get("content", "")}]
    elif tool == "MultiEdit":
        edits = inp.get("edits") or []
    else:
        edits = [{"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}]

    names = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            for m in EXPORT_DEF.finditer(s or ""):
                names.add(m.group(1))

    if not names:
        return 0

    reported = False
    for name in sorted(names):
        try:
            r = subprocess.run(
                ["grep", "-rn",
                 "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx",
                 "--include=*.mts", "--include=*.cts",
                 name, "."],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:25]
            if hits:
                if not reported:
                    print("Exported identifier(s) touched. Verify these references are consistent:", file=sys.stderr)
                    reported = True
                print(f"\n`{name}` references:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
        except Exception:
            pass

    if reported:
        print("\nIf this was a rename or value change, update hardcoded callers before continuing.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git push --force` (or `-f`) targeting main/master."""
import json, re, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not re.search(r"\bgit\s+push\b", cmd):
        return 0
    has_force = bool(re.search(r"(?:^|\s)(?:--force(?:-with-lease)?|-f)(?:\s|=|$)", cmd))
    if not has_force:
        return 0
    if re.search(r"\b(?:main|master)\b", cmd):
        print("Refusing to force-push to main/master - this rewrites shared history. Run outside Claude with explicit human confirmation if truly intended.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())
